import UIKit

class StackedUIImage: UIImage {
    var iconScale: CGFloat = 0.7
    var layers = [UIImage]()

    override func draw(in rect: CGRect) {
        super.draw(in: rect)

        let newWidth = bounds.width
        let iconsSize = floor(newWidth * iconScale)
        let iconsInset = (newWidth - iconsSize) - 1

        for (index, layer) in layers.enumerated() {
            let imageRect = CGRect(x: iconsInset, y: iconsInset, width: iconsSize, height: iconsSize)

            layer.draw(in: imageRect)
        }
    }

    static func fromDeviceTypes(deviceTypes: [DeviceType], context: UIView) -> StackedUIImage? {
        let firstTwo = Array(deviceTypes.prefix(2))
        if firstTwo.count == 1 {
            firstTwo.append(firstTwo[0])
        }

        let imageList = firstTwo.map { UIImage(named: $0.iconOutlinedImageResource) }.compactMap {$0}

        let stackedImage = StackedUIImage()
        stackedImage.layers = imageList.reversed()
        return stackedImage
    }
}
```
