```
import UIKit

class StackedUIImage: UIImage {
    var iconScale: CGFloat = 0.7
    var layers = [UIImage]()

    override func draw(in rect: CGRect) {
        super.draw(in: rect)
        let newWidth = bounds.width
        let iconsSize = floor(newWidth * iconScale)
        let iconsInset = (newWidth - iconsSize) - 1
        if layers.count > 1 {
            let firstImage = layers[0]
            let firstImageRect = CGRect(x: 0, y: iconsInset, width: iconsSize, height: iconsSize)
            firstImage.draw(in: firstImageRect)
        }
        if layers.count > 0 {
            let secondImage = layers[1]
            let secondImageRect = CGRect(x: iconsInset, y: 0, width: iconsSize, height: iconsSize)
            secondImage.draw(in: secondImageRect)
        }
    }

    static func fromDeviceTypes(deviceTypes: [DeviceType], context: UIView) -> StackedUIImage? {
        let firstTwo = Array(deviceTypes.prefix(2))
        if firstTwo.count == 1 {
            firstTwo.append(firstTwo[0])
        }

        let imageList = firstTwo.map { UIImage(named: $0.iconOutlinedImageResource) }.compactMap {$0}

        let stackedImage = StackedUIImage()
        stackedImage.layers = imageList
        return stackedImage
    }
}
```
As you can see I've added an if statement for each draw call, so it only draws two images regardless of the size of the layers array. Also I've removed the reversed function from the fromDeviceTypes method. The first image of the array will be drawn in the bottom left corner, and the second image will be drawn on top of the first image, in the top right corner.

