```python
import os
from collections import defaultdict

def compute_word_frequency(folder_path, min_occurrence=1):
    word_freq = defaultdict(int)

    for filename in os.listdir(folder_path):
        if filename.endswith(".txt"):
            with open(os.path.join(folder_path, filename), 'r') as f:
                for line in f:
                    for word in line.strip().split():
                        word_freq[word] += 1

    filtered_word_freq = {word: freq for word, freq in word_freq.items() if freq >= min_occurrence}
    sorted_word_freq = sorted(filtered_word_freq.items(), key=lambda x: x[1], reverse=True)

    for word, freq in sorted_word_freq:
        print(f"{word}: {freq}")
```
You can use this code by passing the folder path as the first argument and the minimum number of occurrences as the second argument. The output will be a list of words and their frequencies, sorted in descending order by frequency.

