const Discord = require('discord.js');
const client = new Discord.Client();
const mysql = require('mysql');

// Connect to database
const con = mysql.createConnection({
  host: "host",
  user: "username",
  password: "password",
  database: "database"
});
con.connect(function(err) {
  if (err) throw err;
});

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('message', message => {
  // Split message into command and arguments
  const args = message.content.slice(1).split(/ +/);
  const command = args.shift().toLowerCase();

  if (command === 'adopt') {
    adopt(message, args);
  }
  if (command === 'trade') {
    trade(message, args);
  }
});

function adopt(message, args) {
  let adoptable = args[0];
  let user = message.author.id;

  // Check if user has enough currency
  con.query(`SELECT currency FROM users WHERE user_id = ${user}`, function (err, result) {
    if (err) throw err;
    if (result[0].currency < 10) {
      message.channel.send(`Sorry, you don't have enough currency to adopt ${adoptable}`);
    } else {
      // Update user's currency and adoptable ownership in database
      con.query(`UPDATE users SET currency = currency - 10 WHERE user_id = ${user}`);
      con.query(`INSERT INTO adoptables (adoptable_name, user_id) VALUES (${adoptable}, ${user})`);
      message.channel.send(`Congratulations, you have adopted ${adoptable}!`);
    }
  });
}

function trade(message, args) {
  let adoptable = args[0];
  let tradeUser = args[1];
  let user = message.author.id;

  // Check if both users own the adoptable and if the trade is accepted
  con.query(`SELECT * FROM adoptables WHERE adoptable_name = ${adoptable} AND user_id IN (${user}, ${tradeUser})`, function (err, result) {
    if (err) throw err;
    if (result.length < 2) {
      message.channel.send(`Sorry, one of the users does not own ${adoptable}`);
    } else {
      // Update adoptable ownership in the database
      con.query(`UPDATE adoptables SET user_id = ${tradeUser} WHERE adoptable_name = ${adoptable} AND user_id = ${user}`);
      message.channel.send(`Trade successful, ${adoptable} has been traded to ${tradeUser}`);
    }
  });
}

client.login('token');
```
