use Drupal\media\Entity\Media;
use Drupal\auto_image_alt\Plugin\Action\GenerateAltTags;

/**
 * Implements hook_cron().
 */
function auto_image_alt_cron() {
  // Load all media entities of type 'image'.
  $media_storage = \Drupal::entityTypeManager()->getStorage('media');
  $query = $media_storage->getQuery()
    ->condition('bundle', 'image');
  $media_ids = $query->execute();

  // Initialize the GenerateAltTags action.
  $generate_alt_tags = new GenerateAltTags();

  // Loop through the image media entities and execute the action.
  foreach ($media_ids as $media_id) {
    $media = Media::load($media_id);
    $generate_alt_tags->execute($media);
  }
}
```
