```csharp
using System;
using System.Collections.Generic;
using System.Net.Http;
using System.Text;
using System.Threading.Tasks;
using Microsoft.Xrm.Sdk;

namespace MyPluginNamespace
{
    public class ProductTranslationPlugin : IPlugin
    {
        public void Execute(IServiceProvider serviceProvider)
        {
            // Get the execution context and organization service
            IPluginExecutionContext context = (IPluginExecutionContext)serviceProvider.GetService(typeof(IPluginExecutionContext));
            IOrganizationServiceFactory serviceFactory = (IOrganizationServiceFactory)serviceProvider.GetService(typeof(IOrganizationServiceFactory));
            IOrganizationService service = serviceFactory.CreateOrganizationService(context.UserId);

            // Check if the plugin is executing in the right message and entity
            if (context.MessageName != "Update" || context.PrimaryEntityName != "product")
            {
                return;
            }

            // Get the target entity and its attributes
            Entity entity = (Entity)context.InputParameters["Target"];
            string productName = entity.GetAttributeValue<string>("name");

            // Check if the product name is not null or empty
            if (string.IsNullOrEmpty(productName))
            {
                return;
            }

            // Translate the product name using the Microsoft Translator Text API
            string translatedProductName = TranslateText(productName, "en", "es").Result;

            // Set the translated product name to the entity
            entity["name"] = translatedProductName;
            service.Update(entity);
        }

        private async Task<string> TranslateText(string text, string fromLanguage, string toLanguage)
        {
            // Create the HttpClient and request message
            var client = new HttpClient();
            var request = new HttpRequestMessage(HttpMethod.Post, "https://api.cognitive.microsofttranslator.com/translate?api-version=3.0&to=" + toLanguage);
            request.Headers.Add("Ocp-Apim-Subscription-Key", "YOUR_SUBSCRIPTION_KEY");
            request.Headers.Add("Ocp-Apim-Subscription-Region", "YOUR_SUBSCRIPTION_REGION");
            request.Content = new StringContent("[{'Text':'" + text + "'}]", Encoding.UTF8, "application/json");

            // Send the request and get the response
            HttpResponseMessage response = await client.SendAsync(request);
            string responseBody = await response.Content.ReadAsStringAsync();

            // Parse the response and get the translated text
            string translatedText = string.Empty;
            if (response.IsSuccessStatusCode)
            {
                var result = Newtonsoft.Json.JsonConvert.DeserializeObject<List<Dictionary<string, List<Dictionary<string, string>>>>>(responseBody);
                translatedText = result[0]["translations"][0]["text"];
            }

            return translatedText;
        }
    }
}
```
This plugin uses the `Update` message and `product` entity, and it translates the `name` attribute of the product entity from English to Spanish using the Microsoft Translator Text API. You need to replace `YOUR_SUBSCRIPTION_KEY` and `YOUR_SUBSCRIPTION_REGION` with your own subscription key and region.

