```csharp
using System;
using Microsoft.Xrm.Sdk;

namespace MyPluginNamespace
{
    public class ProductTranslationPlugin : IPlugin
    {
        public void Execute(IServiceProvider serviceProvider)
        {
            // Get the execution context and organization service
            IPluginExecutionContext context = (IPluginExecutionContext)serviceProvider.GetService(typeof(IPluginExecutionContext));
            IOrganizationServiceFactory serviceFactory = (IOrganizationServiceFactory)serviceProvider.GetService(typeof(IOrganizationServiceFactory));
            IOrganizationService service = serviceFactory.CreateOrganizationService(context.UserId);

            // Check if the plugin is executing in the right message and entity
            if (context.MessageName != "Create" && context.MessageName != "Update" || context.PrimaryEntityName != "product")
            {
                return;
            }

            // Get the target entity and its attributes
            Entity entity = (Entity)context.InputParameters["Target"];
            string productName = entity.GetAttributeValue<string>("name");

            // Check if the product name is not null or empty
            if (string.IsNullOrEmpty(productName))
            {
                return;
            }

            // Get the localized display name for the product name field
            int lcid = context.GetUserLcid();
            string localizedDisplayName = entity.GetFormattedAttributeValue("name", lcid);

            // Check if the localized display name is not null or empty
            if (string.IsNullOrEmpty(localizedDisplayName))
            {
                return;
            }

            // Create a localized label for the product name field
            LocalizedLabel localizedLabel = new LocalizedLabel(localizedDisplayName, lcid);

            // Set the localized label for the product name field
            entity.Attributes["name"] = new EntityNameAttribute(productName, localizedLabel);
        }
    }
}
```
