    {
        string rootDirectory = @"C:\example";
        string csvFile = @"C:\example\zero_byte_files.csv";

        using (StreamWriter writer = new StreamWriter(csvFile))
        {
            writer.WriteLine("File Path");

            TraverseDirectory(rootDirectory, writer);
        }
    }

    static void TraverseDirectory(string directory, StreamWriter writer)
    {
        foreach (string file in Directory.EnumerateFiles(directory))
        {
            FileInfo fileInfo = new FileInfo(file);
            if (fileInfo.Length == 0)
            {
                writer.WriteLine(fileInfo.FullName);
            }
        }

        foreach (string subdirectory in Directory.EnumerateDirectories(directory))
        {
            TraverseDirectory(subdirectory, writer);
        }
    }
}
```
