using System.IO;
using Microsoft.Office.Interop.Excel;

class Program
{
    static void Main(string[] args)
    {
        string rootDirectory = @"C:\example";

        var excel = new Microsoft.Office.Interop.Excel.Application();

        TraverseDirectory(rootDirectory, excel);

        excel.Quit();
    }

    static void TraverseDirectory(string directory, Microsoft.Office.Interop.Excel.Application excel)
    {
        foreach (string file in Directory.EnumerateFiles(directory, "*.xlsx"))
        {
            var workbook = excel.Workbooks.Open(file);
            var saveAsFile = Path.ChangeExtension(file, "xlsb");
            workbook.SaveAs(saveAsFile, XlFileFormat.xlExcel12);
            workbook.Close();
        }

        foreach (string subdirectory in Directory.EnumerateDirectories(directory))
        {
            TraverseDirectory(subdirectory, excel);
        }
    }
}
```
In this example, the `rootDirectory` variable is set to the directory that you want to start traversing at, the `TraverseDirectory` method is called recursively to traverse the directory tree and the `Directory.EnumerateFiles` method is used to get the xlsx files from the current directory. The Microsoft.Office.Interop.Excel library is used to open the xlsx file, change the file format to xlsb and save it in the same location of the original file with xlsb extension and close the workbook.

